import React, { useEffect, useState } from "react";
import axios from "axios";

export default function DashboardRecepcao() {
  const [disciplinas, setDisciplinas] = useState([]);
  const [periodos, setPeriodos] = useState([]);

  useEffect(() => {
    axios.get("/api/disciplinas").then(res => setDisciplinas(res.data));
    axios.get("/api/periodos").then(res => setPeriodos(res.data));
  }, []);

  return (
    <div className="max-w-6xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Dashboard</h1>

      {/* Cards Dinâmicos de Disciplinas */}
      <h2 className="text-lg font-bold mb-2 text-[#1d3557]">Disciplinas</h2>
      <div className="flex flex-wrap gap-6 mb-8">
        {disciplinas.map((disc) => (
          <div key={disc.id} className="flex-1 min-w-[220px] bg-blue-50 rounded-2xl px-6 py-6 shadow-md flex flex-col">
            <span className="font-semibold text-lg text-[#223366] mb-2">{disc.nome}</span>
            <span className="text-gray-500 mb-2">{disc.periodo_nome} - {disc.turno}</span>
            {/* Exemplo: você pode mostrar quantidade de alunos, agendamentos, etc */}
            {/* <span className="text-2xl font-bold text-blue-900 mt-auto">{disc.qtd_alunos || 0}</span> */}
          </div>
        ))}
        {disciplinas.length === 0 && <span className="text-gray-500 italic">Nenhuma disciplina encontrada</span>}
      </div>

      {/* Cards Dinâmicos de Períodos */}
      <h2 className="text-lg font-bold mb-2 text-[#1d3557]">Períodos</h2>
      <div className="flex flex-wrap gap-6 mb-8">
        {periodos.map((p) => (
          <div key={p.id} className="flex-1 min-w-[220px] bg-teal-50 rounded-2xl px-6 py-6 shadow-md flex flex-col">
            <span className="font-semibold text-lg text-[#225050] mb-2">{p.nome}</span>
            <span className="text-gray-500 mb-2">{p.turno}</span>
            {/* Exemplo: mostrar total de disciplinas no período */}
            {/* <span className="text-2xl font-bold text-[#147a6c] mt-auto">{p.qtd_disciplinas || 0}</span> */}
          </div>
        ))}
        {periodos.length === 0 && <span className="text-gray-500 italic">Nenhum período encontrado</span>}
      </div>

      {/* ...restante do seu dashboard, cards, tabelas etc... */}
    </div>
  );
}
